    if not args.input.endswith(os.path.sep) and not args.filter.startswith(os.path.sep):
        pattern += os.path.sep
    pattern += args.filter
    checkpoints = glob.glob(pattern, recursive=True)

    if args.sort:
        checkpoint_metrics = sorted(
            [(checkpoint_metric(c), c) for c in checkpoints if checkpoint_metric(c) is not None]
        )[-args.n:]

        print("Selected checkpoints:")
