def embed_download(url, output_dir='.', merge=True, info_only=False, **kwargs):
    content = get_content(url, headers=fake_headers)
    found = False
    title = match1(content, '<title>([^<>]+)</title>')

    # Grouping all the similar patterns with the corresponding download method
    video_patterns = [
        (youku_embed_patterns, youku_download_by_vid),
        (tudou_embed_patterns, tudou_download_by_id),
        (iqiyi_embed_patterns, lambda vid, **k: iqiyi_download_by_vid((vid[1], vid[0]), **k)),
        (netease_embed_patterns, netease_download),
        (vimeo_embed_patters, lambda url, **k: vimeo_download_by_id(url, referer=url, **k)),
        (dailymotion_embed_patterns, dailymotion_download),
        (bilibili_embed_patterns, lambda aid, **k: bilibili_download(f'http://www.bilibili.com/video/av{aid}/', **k)),
        (iqiyi_patterns, iqiyi.download),
        (bokecc_patterns, lambda meta, **k: bokecc.bokecc_download_by_id(meta[1], **k))
    ]

    for patterns, download_func in video_patterns:
        matches = matchall(content, patterns)
        for match in set(matches):  # We use set to avoid duplicate downloads for some cases
            found = True
            download_func(match, title=title, output_dir=output_dir, merge=merge, info_only=info_only, **kwargs)

    if found:
        return True

    # Try harder, check all iframes
    if 'recur_lv' not in kwargs or kwargs['recur_lv'] < recur_limit:
        r = kwargs.get('recur_lv')
        if r is None:
            r = 1
        else:
            r += 1
        iframes = matchall(content, [r'<iframe.+?src=(?:\"|\')(.*?)(?:\"|\')'])
        for iframe in iframes:
            if not iframe.startswith('http'):
                src = urllib.parse.urljoin(url, iframe)
            else:
                src = iframe
            found = embed_download(src, output_dir=output_dir, merge=merge, info_only=info_only, recur_lv=r, **kwargs)
            if found:
                return True

    if not found and 'recur_lv' not in kwargs:
        raise NotImplementedError(url)
    else:
        return found

