def test_next_min_version_deprecation_warning(self, mock_warning, mock_get_libversion):
    # Skip test if there's no currently planned new min version
    next_min_version_int, min_version_int = (versionutils.convert_version_to_int(
        libvirt_driver.NEXT_MIN_LIBVIRT_VERSION), versionutils.convert_version_to_int(
        libvirt_driver.MIN_LIBVIRT_VERSION))

    if next_min_version_int == min_version_int:
        self.skipTest("NEXT_MIN_LIBVIRT_VERSION == MIN_LIBVIRT_VERSION")

    # Test that a warning is logged if the libvirt version is less than
    # the next required minimum version.
    drvr = libvirt_driver.LibvirtDriver(fake.FakeVirtAPI(), True)
    drvr.init_host("dummyhost")

    # Assert that the next min version is in a warning message
    expected_arg = {
        'version': versionutils.convert_version_to_str(next_min_version_int)
    }

    for call_args, *_ in mock_warning.call_args_list:
        if call_args[1] == expected_arg:
            self.assertTrue(True)
            break
    else:
        self.assertTrue(False)

