def process_account(a):
    log.debug(f"Processing {a['name']}")
    team_name = a['name'].rsplit('-', 1)[0]

    if team_name not in teams:
        log.info(f"Creating org team {team_name}")
        spost(
            f"{endpoint}organizations/{options.sentry_org}/teams/",
            json={'name': team_name})
        teams.add(team_name)

    if a['name'] not in projects:
        log.info(f"Creating account project {a['name']}")
        spost(f"{endpoint}teams/{options.sentry_org}/{team_name}/projects/",
              json={'name': a['name']})

    bagger = partial(
        Bag,
        profile=options.profile, role=None, log_streams=None,
        start=options.start, end=options.end, sentry_dsn=options.sentry_dsn,
        account_id=a['account_id'],
        account_name=a['name'])

    for r in options.regions:
        log.debug(f"Fetching hub instance policy errors for {a['name']}")
        b = bagger(
            region=r, log_group=f"/cloud-custodian/{a['name']}/{r}")

        try:
            process_log_group(b)
        except ClientError as e:
            log.warning(f"Could not process {a['name']} region {r} error: {e}")

        log.debug(f"Fetching spoke lambda policy errors for {a['name']}")
        for fname, config in a['config_files'].items():
            for p in config.get('policies', ()):
                if not p.get('mode'):
                    continue
                b = bagger(region=r, assume_role=a['role'],
                           log_group=f"/aws/lambda/custodian-{p['name']}")
                try:
                    process_log_group(b)
                except ClientError as e:
                    if e.response['Error']['Code']:
                        log.info(f"Account: {a['name']} region: {r} group: {b.log_group} not found")
                        continue

