        x = x.replace(",", ".").replace(chr(0x2018), "'").replace(chr(0x2019), "'")

        # put string in double quotes
        if " " in x:
            x = x[1:] if x[0] in ('"', "'") else x
            x = x[:-1] if x[-1] in ('"', "'") else x
            x = f'"{x.replace(\'"\', "\\\"")}"'
    return str(x)

