method_content:
def get_split_parts(num, num_part):
    assert num_part > 0, "Invalid number of parts"
    same_part = num // num_part
    remain_num = num % num_part
    num_ = num_part * (same_part > 0)
    if remain_num == 0:
        return [same_part] * num_ 
    else:
        return [same_part] * num_ + [remain_num]

